const crypto = require('crypto');
const body = $('Webhook').first().json.body;
const results = $input.first().json.results;
if (!results || results.length === 0) {
  throw new Error('Email oder Passwort falsch');
}
const user = results[0];
const props = user.properties;
const storedHash = props.password_hash.rich_text[0]?.plain_text;
if (!storedHash) throw new Error('Email oder Passwort falsch');
const [hash, salt] = storedHash.split(':');
const inputHash = crypto.createHash('sha256').update(body.password + salt).digest('hex');
if (inputHash !== hash) throw new Error('Email oder Passwort falsch');
if (!props.aktiv.checkbox) throw new Error('Account deaktiviert');
const jwt = require('jsonwebtoken');
const token = jwt.sign(
  { user_id: user.id, email: body.email, username: props.username.rich_text[0]?.plain_text },
  'BOXENFUNK_SECRET_2026',
  { expiresIn: '7d' }
);
return [{ json: { success: true, token, user_id: user.id, username: props.username.rich_text[0]?.plain_text, punkte_total: props.punkte_total.number } }];
